# Define a function to create services in Kong
def create_service(service_name, host):
    url = f'{kong_admin_url}/services'
    headers = {'Content-Type': 'application/json'}
    data = {
        'name': service_name,
        'host': host
    }
    response = requests.post(url, auth=HTTPBasicAuth(username, password), headers=headers, json=data)
    if response.status_code == 201:
        print(f'Service {service_name} created successfully')
    else:
        print(f'Failed to create service {service_name}')

# Define a function to create routes in Kong
def create_route(service_name, path):
    url = f'{kong_admin_url}/services/{service_name}/routes'
    headers = {'Content-Type': 'application/json'}
    data = {
        'protocols': ['http', 'https'],
        'paths': [path]
    }
    response = requests.post(url, auth=HTTPBasicAuth(username, password), headers=headers, json=data)
    if response.status_code == 201:
        print(f'Route {path} created successfully for service {service_name}')
    else:
        print(f'Failed to create route {path} for service {service_name}')

# Define a function to create upstream targets in Kong
def create_upstream(service_name, target):
    url = f'{kong_admin_url}/services/{service_name}/upstreams'
    headers = {'Content-Type': 'application/json'}
